import React, { useEffect, useState } from 'react';
import './RegisterProductionRequirement.css';

const RegisterProductionRequirement = () => {
    const [products, setProducts] = useState([]);
    const [rawMaterials, setRawMaterials] = useState([]);
    const [selectedProduct, setSelectedProduct] = useState('');
    const [requirements, setRequirements] = useState([]);

    useEffect(() => {
        const fetchProductsAndMaterials = async () => {
            try {
                const productResponse = await fetch('http://localhost:8000/api/v1/products');
                const materialResponse = await fetch('http://localhost:8000/api/v1/raw-materials');

                if (!productResponse.ok || !materialResponse.ok) {
                    throw new Error('Failed to fetch data');
                }

                setProducts(await productResponse.json());
                setRawMaterials(await materialResponse.json());
            } catch (error) {
                console.error('Error fetching data:', error);
            }
        };

        fetchProductsAndMaterials();
    }, []);

    const handleAddRequirement = () => {
        setRequirements([...requirements, { rawMaterialId: '', quantity: '' }]);
    };

    const handleRequirementChange = (index, field, value) => {
        const updatedRequirements = [...requirements];
        updatedRequirements[index][field] = value;
        setRequirements(updatedRequirements);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const response = await fetch('http://localhost:8000/api/v1/production-requirements', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ productId: selectedProduct, requirements })
            });

            if (!response.ok) {
                throw new Error('Failed to submit production requirements');
            }

            alert('Production requirements registered successfully!');
        } catch (error) {
            console.error('Error submitting production requirements:', error);
            alert('Failed to register production requirements. Please try again.');
        }
    };

    return (
        <div className="register-production-requirement-container">
            <h1>Register Production Requirement</h1>
            <form onSubmit={handleSubmit}>
                <label>
                    Product:
                    <select value={selectedProduct} onChange={(e) => setSelectedProduct(e.target.value)} required>
                        <option value="">Select a product</option>
                        {products.map((product) => (
                            <option key={product.id} value={product.id}>{product.name}</option>
                        ))}
                    </select>
                </label>
                <div className="requirements-list">
                    {requirements.map((requirement, index) => (
                        <div key={index} className="requirement-item">
                            <select
                                value={requirement.rawMaterialId}
                                onChange={(e) => handleRequirementChange(index, 'rawMaterialId', e.target.value)}
                                required
                            >
                                <option value="">Select Raw Material</option>
                                {rawMaterials.map((material) => (
                                    <option key={material.id} value={material.id}>{material.name}</option>
                                ))}
                            </select>
                            <input
                                type="number"
                                value={requirement.quantity}
                                onChange={(e) => handleRequirementChange(index, 'quantity', e.target.value)}
                                placeholder="Quantity per unit"
                                required
                            />
                        </div>
                    ))}
                    <button type="button" onClick={handleAddRequirement}>Add Requirement</button>
                </div>
                <button type="submit">Submit</button>
            </form>
            <button onClick={() => console.log('Navigating to production requirements list')}>View Production Requirements</button>
        </div>
    );
};

export default RegisterProductionRequirement;
